import torch
import torch.nn.functional as F

# -----------------------------------------------------------------------------# 040_conv2d_residual_block
#
#   x -> Conv3x3 (3->32) -> Conv3x3 (32->3) -> +x
#
# Strategy:
#   * FP16 cuDNN tensor-core convs: 2x TF32 throughput and the (B,32,H,W)
#     intermediate is stored in half precision, slashing the dominant HBM term.
#   * Per-regime dispatch:
#       - P = B*H*W <= 65536 (launch-bound): reduce-overhead CUDA graph of the
#         fastest body so ~3 kernel launches collapse to one replay.
#       - B == 1,  P > 65536: NCHW body; cuDNN emits NCHW for tall-skinny
#         implicit GEMMs, so forcing channels_last would pay a full transpose.
#       - B >= 2,  P > 65536: explicit channels_last; cuDNN already hands
#         NHWC between convs, so conv2 gets the fast NHWC tensor-core kernel.
#   * Exhaustive cuDNN algorithm search (benchmark_limit=0).
#   * torch.compile default mode for large shapes fuses the fp16->fp32 cast
#     and residual add into a single bandwidth kernel.
#   * Eager fallback always returns a correct result if any compile path fails.
# -----------------------------------------------------------------------------

# cuDNN tensor-core convs; exhaustive algo search for these fixed shapes.
torch.backends.cudnn.allow_tf32 = True
torch.backends.cuda.matmul.allow_tf32 = True
torch.backends.cudnn.benchmark = True
torch.backends.cudnn.deterministic = False
if hasattr(torch.backends.cudnn, "benchmark_limit"):
    torch.backends.cudnn.benchmark_limit = 0

# Many fixed shapes run in one process; raise recompile caps so later shapes
# keep their optimized graphs instead of thrashing to eager.
try:
    import torch._dynamo as _dynamo

    _dynamo.config.cache_size_limit = max(getattr(_dynamo.config, "cache_size_limit", 8), 512)
    if hasattr(_dynamo.config, "accumulated_cache_size_limit"):
        _dynamo.config.accumulated_cache_size_limit = max(
            _dynamo.config.accumulated_cache_size_limit, 2048
        )
except Exception:
    pass

_CL = torch.channels_last
_HALF = torch.float16

# B*H*W at/under which launch overhead dominates enough that a CUDA-graph replay
# beats a plain compiled dispatch.
_P_CUDAGRAPH_MAX = 1 << 16  # 65536


# ---- eager bodies (correctness fallback and compile targets) ----


def _core_cl(
    x,
    conv_in_weight,
    conv_in_bias,
    conv_out_weight,
    conv_out_bias,
):
    """Explicit-NHWC body: best for B >= 2 where cuDNN already emits NHWC."""
    x_h = x.to(dtype=_HALF, memory_format=_CL)
    w1 = conv_in_weight.to(dtype=_HALF, memory_format=_CL)
    w2 = conv_out_weight.to(dtype=_HALF, memory_format=_CL)
    b1 = conv_in_bias.to(_HALF)
    b2 = conv_out_bias.to(_HALF)

    out = F.conv2d(x_h, w1, b1, padding=1)
    out = F.conv2d(out, w2, b2, padding=1)

    # Residual in fp32 against the original fp32 input.
    return out.to(torch.float32) + x


def _core_nchw(
    x,
    conv_in_weight,
    conv_in_bias,
    conv_out_weight,
    conv_out_bias,
):
    """Natural-layout body: avoids the NCHW->NHWC transpose for B == 1."""
    x_h = x.to(dtype=_HALF)
    w1 = conv_in_weight.to(dtype=_HALF)
    w2 = conv_out_weight.to(dtype=_HALF)
    b1 = conv_in_bias.to(_HALF)
    b2 = conv_out_bias.to(_HALF)

    out = F.conv2d(x_h, w1, b1, padding=1)
    out = F.conv2d(out, w2, b2, padding=1)

    return out.to(torch.float32) + x


# ---- lazily-built compiled entry points with graceful degradation ----

_compiled_graph_cl = None
_compiled_graph_nchw = None
_compiled_default_cl = None
_compiled_default_nchw = None
_graph_cl_disabled = False
_graph_nchw_disabled = False
_default_cl_disabled = False
_default_nchw_disabled = False


def _get_graph_cl():
    global _compiled_graph_cl, _graph_cl_disabled
    if _compiled_graph_cl is not None or _graph_cl_disabled:
        return _compiled_graph_cl
    if not hasattr(torch, "compile"):
        _graph_cl_disabled = True
        return None
    try:
        _compiled_graph_cl = torch.compile(_core_cl, mode="reduce-overhead", dynamic=False)
    except Exception:
        _graph_cl_disabled = True
        _compiled_graph_cl = None
    return _compiled_graph_cl


def _get_graph_nchw():
    global _compiled_graph_nchw, _graph_nchw_disabled
    if _compiled_graph_nchw is not None or _graph_nchw_disabled:
        return _compiled_graph_nchw
    if not hasattr(torch, "compile"):
        _graph_nchw_disabled = True
        return None
    try:
        _compiled_graph_nchw = torch.compile(_core_nchw, mode="reduce-overhead", dynamic=False)
    except Exception:
        _graph_nchw_disabled = True
        _compiled_graph_nchw = None
    return _compiled_graph_nchw


def _get_default_cl():
    global _compiled_default_cl, _default_cl_disabled
    if _compiled_default_cl is not None or _default_cl_disabled:
        return _compiled_default_cl
    if not hasattr(torch, "compile"):
        _default_cl_disabled = True
        return None
    try:
        _compiled_default_cl = torch.compile(_core_cl, dynamic=False)
    except Exception:
        _default_cl_disabled = True
        _compiled_default_cl = None
    return _compiled_default_cl


def _get_default_nchw():
    global _compiled_default_nchw, _default_nchw_disabled
    if _compiled_default_nchw is not None or _default_nchw_disabled:
        return _compiled_default_nchw
    if not hasattr(torch, "compile"):
        _default_nchw_disabled = True
        return None
    try:
        _compiled_default_nchw = torch.compile(_core_nchw, dynamic=False)
    except Exception:
        _default_nchw_disabled = True
        _compiled_default_nchw = None
    return _compiled_default_nchw


# ---- dispatch (fallback logic isolated from run()) ----


def _dispatch(args):
    global _graph_cl_disabled, _graph_nchw_disabled, _default_cl_disabled, _default_nchw_disabled

    x = args[0]
    b = x.shape[0]
    p = b * x.shape[2] * x.shape[3]

    # ---- small shapes: CUDA-graph replay collapses per-iteration launch gaps ----
    if p <= _P_CUDAGRAPH_MAX:
        if b == 1:
            fn = _get_graph_nchw()
            if fn is not None:
                try:
                    # clone() defends against returning a CUDA-graph static buffer.
                    return fn(*args).clone()
                except Exception:
                    _graph_nchw_disabled = True
        else:
            fn = _get_graph_cl()
            if fn is not None:
                try:
                    return fn(*args).clone()
                except Exception:
                    _graph_cl_disabled = True

        # Graph failed or unavailable: fall through to default compile.
        if b == 1:
            fn = _get_default_nchw()
            if fn is not None:
                try:
                    return fn(*args)
                except Exception:
                    _default_nchw_disabled = True
        else:
            fn = _get_default_cl()
            if fn is not None:
                try:
                    return fn(*args)
                except Exception:
                    _default_cl_disabled = True

        return _core_nchw(*args)

    # ---- large shapes: default compile with the fastest body per regime ----
    if b == 1:
        fn = _get_default_nchw()
        if fn is not None:
            try:
                return fn(*args)
            except Exception:
                _default_nchw_disabled = True
        return _core_nchw(*args)

    fn = _get_default_cl()
    if fn is not None:
        try:
            return fn(*args)
        except Exception:
            _default_cl_disabled = True
    return _core_cl(*args)


# ---- entry point ----


@torch.no_grad()
def run(
    x: torch.Tensor,
    conv_in_weight: torch.Tensor,
    conv_in_bias: torch.Tensor,
    conv_out_weight: torch.Tensor,
    conv_out_bias: torch.Tensor,
):
    return _dispatch(
        (x, conv_in_weight, conv_in_bias, conv_out_weight, conv_out_bias)
    )

